using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> ConfidenceScores { get; set; }
}

public class TrainingMetricsResponse
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly string _modelPath;
    private readonly string _dataPath;
    private readonly ILogger<TicketModelService> _logger;

    public TrainingMetricsResponse? LastTrainingMetrics { get; private set; }

    public TicketModelService(ILogger<TicketModelService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
    }

    public void TrainAndSave()
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // With only 6 rows, use full data for training and evaluate on training set.
        // In production, use TrainTestSplit with a larger dataset:
        //   var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
        var trainData = data;

        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(trainData);

        var predictions = model.Transform(trainData);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        LastTrainingMetrics = new TrainingMetricsResponse
        {
            MacroAccuracy = (float)metrics.MacroAccuracy,
            MicroAccuracy = (float)metrics.MicroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction
        };

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        mlContext.Model.Save(model, trainData.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    public string ModelPath => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly TicketModelService _modelService;

    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        TicketModelService modelService)
    {
        _predictionPool = predictionPool;
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var confidenceScores = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidenceScores[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            ConfidenceScores = confidenceScores
        });
    }

    [HttpGet("metrics")]
    public ActionResult<TrainingMetricsResponse> GetMetrics()
    {
        if (_modelService.LastTrainingMetrics is null)
            return NotFound("No training metrics available.");

        return Ok(_modelService.LastTrainingMetrics);
    }
}

